function perm(mysqli $conn,string $action):bool{if(($_SESSION['user_type']??'')==='Platform Admin')return true;$map=['open'=>'can_open','view'=>'can_view','value'=>'can_view_value','create'=>'can_create','update'=>'can_update','delete'=>'can_delete'];$field=$map[$action]??'';$codes=['perm.inventory.silver_rates','perm.rates.silver','perm.silver_rates','perm.inventory.metal_rates','perm.inventory'];foreach($codes as $c){if(isset($_SESSION['permissions'][$c])&&array_key_exists($field,$_SESSION['permissions'][$c]))return(int)$_SESSION['permissions'][$c][$field]===1;}$bid=(int)($_SESSION['business_id']??0);$rid=(int)($_SESSION['role_id']??0);if(!$bid||!$rid)return false;$marks=implode(',',array_fill(0,count($codes),'?'));$stmt=$conn->prepare("SELECT rp.`$field` FROM role_permissions rp JOIN permissions p ON p.id=rp.permission_id WHERE rp.business_id=? AND rp.role_id=? AND p.is_active=1 AND p.permission_code IN ($marks) LIMIT 1");if(!$stmt)return false;$types='ii'.str_repeat('s',count($codes));$vals=array_merge([$bid,$rid],$codes);$stmt->bind_param($types,...$vals);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();$stmt->close();return(int)($row[$field]??0)===1;}
