if($action==='list'){if(!perm($conn,'view')&&!perm($conn,'open'))respond(false,'Permission denied.',[],403);$search=trim((string)($_POST['search']??''));$purity=trim((string)($_POST['purity']??''));$month=trim((string)($_POST['month']??''));$pp=(int)($_POST['per_page']??10);if(!in_array($pp,[10,25,50,100],true))$pp=10;$page=max(1,(int)($_POST['page']??1));$where=' WHERE s.business_id=?';$types='i';$params=[$bid];if($search!==''){$where.=" AND (s.purity LIKE ? OR COALESCE(s.remarks,'') LIKE ? OR DATE_FORMAT(s.rate_date,'%d-%m-%Y') LIKE ?)";$like='%'.$search.'%';array_push($params,$like,$like,$like);$types.='sss';}if($purity!==''){$where.=' AND s.purity=?';$params[]=$purity;$types.='s';}if($month!==''&&preg_match('/^\d{4}-\d{2}$/',$month)){$where.=" AND DATE_FORMAT(s.rate_date,'%Y-%m')=?";$params[]=$month;$types.='s';}$stmt=$conn->prepare('SELECT COUNT(*) total FROM silver_rate_history s'.$where);$stmt->bind_param($types,...$params);$stmt->execute();$total=(int)$stmt->get_result()->fetch_assoc()['total'];$stmt->close();$pages=max(1,(int)ceil($total/$pp));$page=min($page,$pages);$offset=($page-1)*$pp;$sql="SELECT s.*,DATE_FORMAT(s.rate_date,'%d %b %Y') rate_date_display,u.full_name updated_by_name FROM silver_rate_history s LEFT JOIN users u ON u.id=s.updated_by AND u.business_id=s.business_id $where ORDER BY s.rate_date DESC,CAST(s.purity AS UNSIGNED) DESC,s.id DESC LIMIT ? OFFSET ?";$vals=$params;$vals[]=$pp;$vals[]=$offset;$stmt=$conn->prepare($sql);$stmt->bind_param($types.'ii',...$vals);$stmt->execute();$rates=$stmt->get_result()->fetch_all(MYSQLI_ASSOC);$stmt->close();$stmt=$conn->prepare("SELECT COUNT(*) total,COUNT(DISTINCT purity) purities,COALESCE(MAX(rate_per_gram),0) highest,SUM(rate_date=CURDATE()) today FROM silver_rate_history WHERE business_id=?");$stmt->bind_param('i',$bid);$stmt->execute();$stats=$stmt->get_result()->fetch_assoc();$stmt->close();respond(true,'Rates loaded.',['rates'=>$rates,'stats'=>array_map('floatval',$stats),'meta'=>['page'=>$page,'per_page'=>$pp,'total'=>$total,'total_pages'=>$pages,'from'=>$total?($offset+1):0,'to'=>min($offset+$pp,$total)]]);}
