if($action==='save'){$id=(int)($_POST['rate_id']??0);$isNew=$id<=0;if($isNew&&!perm($conn,'create'))respond(false,'You do not have permission to create rates.',[],403);if(!$isNew&&!perm($conn,'update'))respond(false,'You do not have permission to update rates.',[],403);$date=trim((string)($_POST['rate_date']??''));$purity=trim((string)($_POST['purity']??''));$rate=(float)($_POST['rate_per_gram']??0);$remarks=trim((string)($_POST['remarks']??''));if(!preg_match('/^\d{4}-\d{2}-\d{2}$/',$date))respond(false,'Enter a valid rate date.');if($purity===''||strlen($purity)>20)respond(false,'Enter a valid purity.');if($rate<=0)respond(false,'Rate per gram must be greater than zero.');$old=null;if(!$isNew){$stmt=$conn->prepare('SELECT * FROM silver_rate_history WHERE id=? AND business_id=?');$stmt->bind_param('ii',$id,$bid);$stmt->execute();$old=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$old)respond(false,'Rate not found.',[],404);}$stmt=$conn->prepare('SELECT id FROM silver_rate_history WHERE business_id=? AND rate_date=? AND purity=? AND id<>?');$stmt->bind_param('issi',$bid,$date,$purity,$id);$stmt->execute();$dup=$stmt->get_result()->fetch_assoc();$stmt->close();if($dup)respond(false,'A rate already exists for this date and purity.');$remark=$remarks!==''?$remarks:null;if($isNew){$stmt=$conn->prepare('INSERT INTO silver_rate_history (business_id,rate_date,purity,rate_per_gram,remarks,updated_by) VALUES (?,?,?,?,?,?)');$stmt->bind_param('issdsi',$bid,$date,$purity,$rate,$remark,$uid);$stmt->execute();$id=(int)$stmt->insert_id;$stmt->close();}else{$stmt=$conn->prepare('UPDATE silver_rate_history SET rate_date=?,purity=?,rate_per_gram=?,remarks=?,updated_by=? WHERE id=? AND business_id=?');$stmt->bind_param('ssdsiii',$date,$purity,$rate,$remark,$uid,$id,$bid);$stmt->execute();$stmt->close();}$new=['rate_date'=>$date,'purity'=>$purity,'rate_per_gram'=>$rate,'remarks'=>$remark];audit($conn,$bid,$branch,$uid,$isNew?'Create':'Update',$id,($isNew?'Created':'Updated').'